#include <stdio.h>
#include <stdlib.h>

typedef struct Node {
    int val;
    struct Node* next;
    struct Node* prev;
} Node;

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        Node *head=NULL, *tail=NULL;
        for(int i=0;i<N;i++){
            int x; scanf("%d", &x);
            Node* nd = (Node*)malloc(sizeof(Node));
            nd->val = x; nd->next = nd->prev = NULL;
            if(!head){head=tail=nd;}
            else{tail->next=nd; nd->prev=tail; tail=nd;}
        }
        int turn = 0; // 0 Aman, 1 Akshat
        while(head!=tail){ // more than one element
            int rot = (turn==0)?1:2;
            for(int r=0;r<rot;r++){
                // rotate: move head to tail
                Node* tmp = head;
                head = head->next;
                head->prev = NULL;
                tail->next = tmp;
                tmp->prev = tail;
                tmp->next = NULL;
                tail = tmp;
            }
            // discard head
            Node* del = head;
            head = head->next;
            head->prev = NULL;
            free(del);
            turn ^= 1;
        }
        int lastMover = (N%2==0)?1:0;
        printf("%d %d\n", lastMover, head->val);
        free(head);
    }
    return 0;
}

