import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int T = fs.nextInt();
        StringBuilder sb = new StringBuilder();
        while (T-- > 0) {
            int N = fs.nextInt();
            ArrayDeque<Long> dq = new ArrayDeque<>();
            for (int i = 0; i < N; i++) dq.addLast(fs.nextLong());
            boolean aman = true;
            while (dq.size() > 1) {
                int rot = aman ? 1 : 2;
                for (int i = 0; i < rot; i++) {
                    long x = dq.removeFirst();
                    dq.addLast(x);
                }
                dq.removeFirst(); // discard
                aman = !aman;
            }
            int lastMover = (N % 2 == 0) ? 1 : 0;
            sb.append(lastMover).append(' ').append(dq.peekFirst()).append('\n');
        }
        System.out.print(sb.toString());
    }
    // Fast scanner for large input
    static class FastScanner {
        private final InputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream in) { this.in = in; }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        long nextLong() throws IOException { return Long.parseLong(next()); }
        int nextInt() throws IOException { return Integer.parseInt(next()); }
        String next() throws IOException {
            StringBuilder sb = new StringBuilder();
            int c;
            while ((c = readByte()) != -1 && c <= ' ') {}
            while (c != -1 && c > ' ') {
                sb.append((char) c);
                c = readByte();
            }
            return sb.toString();
        }
    }
}

