let out = [];
for (let t = 0; t < T; t++) {
  const N = Number(input[idx++]);
  const dq = [];
  for (let i = 0; i < N; i++) dq.push(Number(input[idx++]));
  let aman = true;
  while (dq.length > 1) {
    const rot = aman ? 1 : 2;
    for (let r = 0; r < rot; r++) {
      const x = dq.shift();
      dq.push(x);
    }
    dq.shift(); // discard
    aman = !aman;
  }
  const lastMover = (N % 2 === 0) ? 1 : 0;
  out.push(`${lastMover} ${dq[0]}`);
}
